    31→// Config::Subscription
    32→void GrpcSubscriptionImpl::start(const absl::flat_hash_set<std::string>& resources) {
    33→  if (init_fetch_timeout_.count() > 0) {
    34→    init_fetch_timeout_timer_ = dispatcher_.createTimer([this]() -> void {
    35→      onConfigUpdateFailed(Envoy::Config::ConfigUpdateFailureReason::FetchTimedout, nullptr);
    36→    });
    37→    init_fetch_timeout_timer_->enableTimer(init_fetch_timeout_);
    38→  }
    39→
    40→  watch_ = grpc_mux_->addWatch(type_url_, resources, *this, resource_decoder_, options_);
    41→
    42→  // The attempt stat here is maintained for the purposes of having consistency between ADS and
    43→  // gRPC/filesystem/REST Subscriptions. Since ADS is push based and muxed, the notion of an
    44→  // "attempt" for a given xDS API combined by ADS is not really that meaningful.
    45→  stats_.update_attempt_.inc();
    46→
    47→  // ADS initial request batching relies on the users of the GrpcMux *not* calling start on it,
    48→  // whereas non-ADS xDS users must call it themselves.
    49→  if (!is_aggregated_) {
    50→    grpc_mux_->start();
    51→  }
    52→}
